import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Search, Filter, Rocket, Star, Shield, LayoutDashboard, Send, PlusCircle, CheckCircle, Briefcase, Mail, Users } from 'lucide-react';
import Navbar from '../components/Navbar';
import UserCard from '../components/UserCard';

const FindBuddies = () => {
  const [searchTerm, setSearchTerm] = useState('');

  const buddies = [
    { name: "John Doe", role: "Junior Tutor", skills: ["Physics", "Calculus", "JavaScript"], id: 1 },
    { name: "Jane Smith", role: "UI/UX Mentor", skills: ["Figma", "Design", "Product"], id: 2 },
    { name: "Alex Johnson", role: "Project Manager", skills: ["Strategy", "Python", "SQL"], id: 3 },
    { name: "Sarah Williams", role: "Frontend Guru", skills: ["React", "CSS", "Animations"], id: 4 },
    { name: "Mike Thompson", role: "Backend Expert", skills: ["Node.js", "MongoDB", "Express"], id: 5 },
    { name: "Emily Brown", role: "Data Scientist", skills: ["Python", "Pandas", "Scikit-Learn"], id: 6 },
    { name: "Chris Lee", role: "Mobile Developer", skills: ["Swift", "Kotlin", "React Native"], id: 7 },
    { name: "Olivia Garcia", role: "Graphic Designer", skills: ["Illustrator", "Photoshop", "InDesign"], id: 8 },
    { name: "David Miller", role: "Content Writer", skills: ["Copywriting", "SEO", "Editing"], id: 9 },
    { name: "Sophia Martinez", role: "Marketing Specialist", skills: ["Social Media", "Ads", "Analytics"], id: 10 },
    { name: "James Wilson", role: "Fullstack Dev", skills: ["HTML", "JSON", "Git"], id: 11 },
    { name: "Isabella Davis", role: "Product Manager", skills: ["Prioritization", "Roadmaps", "User Testing"], id: 12 },
  ];

  const filteredBuddies = buddies.filter(buddy => 
    buddy.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    buddy.skills.some(skill => skill.toLowerCase().includes(searchTerm.toLowerCase()))
  );

  return (
    <div className="min-h-screen pt-24 px-6 md:px-12 bg-background-dark/95">
      <Navbar />

      {/* Search Header */}
      <section className="container mx-auto py-10">
        <motion.div 
          initial={{ opacity: 0, y: 30 }}
          animate={{ opacity: 1, y: 0 }}
          className="max-w-4xl mx-auto glass shadow-2xl p-4 md:p-6 mb-16 rounded-3xl animate-fade-in relative overflow-hidden"
        >
          <div className="absolute top-0 right-0 w-32 h-32 bg-primary-600/10 blur-3xl -z-10 animate-float bg-blue-600/20"></div>

          <div className="flex flex-col md:flex-row items-center space-y-4 md:space-y-0 md:space-x-4">
            <div className="relative flex-1 group w-full">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500 group-focus-within:text-primary-400 transition-colors" />
              <input 
                type="text" 
                placeholder="Search Skills (Physics, JavaScript, Python...)" 
                className="w-full bg-white/5 border border-white/10 text-white rounded-2xl py-4 pl-12 pr-6 focus:ring-2 focus:ring-primary-600 transition-all outline-none font-bold italic tracking-tight uppercase"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
            <button className="flex items-center space-x-2 px-8 py-4 bg-white/10 hover:bg-white/20 border border-white/10 rounded-2xl transition-all shadow-xl font-extrabold uppercase tracking-widest text-sm">
              <Filter size={18} />
              <span>Filters</span>
            </button>
          </div>
        </motion.div>

        {/* Results Info */}
        <div className="max-w-7xl mx-auto mb-8 animate-fade-in">
           <h2 className="text-2xl font-black uppercase tracking-tighter opacity-70">
              Discovered <span className="text-primary-400">{filteredBuddies.length}</span> Buddies
           </h2>
        </div>

        {/* Buddies Grid */}
        <div className="max-w-7xl mx-auto grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8 pb-32">
          <AnimatePresence mode="popLayout">
            {filteredBuddies.map((buddy) => (
              <UserCard key={buddy.id} user={buddy} />
            ))}
          </AnimatePresence>
        </div>
      </section>
    </div>
  );
};

export default FindBuddies;
